"use strict";parserFactory.register("nobadnovel.com",()=>new NobadnovelParser);class NobadnovelParser extends Parser{constructor(){super(),this.minimumThrottle=500}async getChapterUrls(e){let t=(await HttpClient.wrapFetch(e.baseURI)).responseXML.querySelector("#table");return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector("div.text-base")}extractTitleImpl(e){return e.querySelector("title")}extractDescription(e){return e.querySelector("div.content").textContent.trim()}findChapterTitle(e){return e.querySelector("h1")}findCoverImageUrl(e){return e.querySelector("img.object-cover")?.src??null}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.content")]}}